package genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program_assignment.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program_assignment.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_maintenance_program_assignment.service.VehicleMaintenanceProgramAssignmentService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/vehicle-maintenance-program-assignments") public class VehicleMaintenanceProgramAssignmentController { private final VehicleMaintenanceProgramAssignmentService service; public VehicleMaintenanceProgramAssignmentController(VehicleMaintenanceProgramAssignmentService service){this.service=service;} @GetMapping public List<VehicleMaintenanceProgramAssignmentResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleMaintenanceProgramAssignmentResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleMaintenanceProgramAssignmentResponse create(@RequestBody VehicleMaintenanceProgramAssignmentUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleMaintenanceProgramAssignmentResponse update(@PathVariable UUID id,@RequestBody VehicleMaintenanceProgramAssignmentUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
